import { Router } from 'express';
import { getDb } from '../db/database.js';
import { v4 as uuid } from 'uuid';

const router = Router();

router.get('/', (req, res) => {
  const db = getDb();
  let query = 'SELECT * FROM kpi_definitions WHERE is_active = 1';
  const params = [];

  if (req.query.category) {
    query += ' AND category = ?';
    params.push(req.query.category);
  }

  query += ' ORDER BY category, name';
  const kpis = db.prepare(query).all(...params);
  res.json(kpis);
});

router.get('/categories', (req, res) => {
  const db = getDb();
  const categories = db.prepare('SELECT DISTINCT category FROM kpi_definitions ORDER BY category').all();
  res.json(categories.map(c => c.category));
});

router.get('/:id', (req, res) => {
  const db = getDb();
  const kpi = db.prepare('SELECT * FROM kpi_definitions WHERE id = ?').get(req.params.id);
  if (!kpi) return res.status(404).json({ error: 'KPI not found' });
  res.json(kpi);
});

router.post('/', (req, res) => {
  const db = getDb();
  const id = uuid();
  const { name, code, category, description, formula, unit, direction, applicable_roles } = req.body;

  db.prepare(`
    INSERT INTO kpi_definitions (id, name, code, category, description, formula, unit, direction, applicable_roles)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
  `).run(id, name, code, category, description, formula, unit || 'currency', direction || 'higher_is_better', JSON.stringify(applicable_roles || []));

  const kpi = db.prepare('SELECT * FROM kpi_definitions WHERE id = ?').get(id);
  res.status(201).json(kpi);
});

export default router;

