import { Router } from 'express';
import { getDb } from '../db/database.js';
import { runCalculationPipeline } from '../engine/calculationPipeline.js';

const router = Router();

// List calculation runs
router.get('/runs', (req, res) => {
  const db = getDb();
  let query = `
    SELECT cr.*, cp.name as plan_name
    FROM calculation_runs cr
    JOIN commission_plans cp ON cr.plan_id = cp.id
    WHERE cr.is_simulation = 0
    ORDER BY cr.started_at DESC
  `;
  const runs = db.prepare(query).all();
  res.json(runs);
});

// Get a run with results
router.get('/runs/:id', (req, res) => {
  const db = getDb();
  const run = db.prepare(`
    SELECT cr.*, cp.name as plan_name
    FROM calculation_runs cr
    JOIN commission_plans cp ON cr.plan_id = cp.id
    WHERE cr.id = ?
  `).get(req.params.id);
  if (!run) return res.status(404).json({ error: 'Run not found' });

  run.payouts = db.prepare(`
    SELECT ep.*, e.name as employee_name, r.name as role_name, e.base_salary
    FROM employee_payouts ep
    JOIN employees e ON ep.employee_id = e.id
    JOIN roles r ON e.role_id = r.id
    WHERE ep.run_id = ?
    ORDER BY ep.net_payout DESC
  `).all(run.id);

  res.json(run);
});

// Get payout detail with KPI breakdown
router.get('/payouts/:id', (req, res) => {
  const db = getDb();
  const payout = db.prepare(`
    SELECT ep.*, e.name as employee_name, r.name as role_name, e.base_salary
    FROM employee_payouts ep
    JOIN employees e ON ep.employee_id = e.id
    JOIN roles r ON e.role_id = r.id
    WHERE ep.id = ?
  `).get(req.params.id);
  if (!payout) return res.status(404).json({ error: 'Payout not found' });

  payout.kpi_results = db.prepare(`
    SELECT kr.*, k.name as kpi_name, k.code as kpi_code, k.category as kpi_category, k.unit
    FROM kpi_results kr
    JOIN kpi_definitions k ON kr.kpi_id = k.id
    WHERE kr.payout_id = ?
  `).all(payout.id);

  payout.approval_history = db.prepare(`
    SELECT * FROM approval_log WHERE payout_id = ? ORDER BY created_at
  `).all(payout.id);

  res.json(payout);
});

// Run calculation
router.post('/run', (req, res) => {
  const { plan_id, period, created_by } = req.body;

  try {
    const result = runCalculationPipeline({ plan_id, period, created_by, is_simulation: false });
    res.json(result);
  } catch (err) {
    console.error('Calculation error:', err);
    res.status(500).json({ error: err.message });
  }
});

export default router;

