                  <button
                    key={p.id}
                    onClick={() => { setPersona(p); setPersonaOpen(false); }}
                    className={`w-full flex items-center gap-3 px-3 py-2 hover:bg-slate-50 transition-colors ${
                      currentPersona.id === p.id ? 'bg-primary-50' : ''
