// Update plan KPIs
router.put('/:id/kpis', (req, res) => {
  const db = getDb();
  const { kpis } = req.body;

  db.prepare('DELETE FROM plan_kpis WHERE plan_id = ?').run(req.params.id);
  const stmt = db.prepare('INSERT INTO plan_kpis (id, plan_id, kpi_id, weight, target_value, slab_set_id) VALUES (?, ?, ?, ?, ?, ?)');
  for (const kpi of kpis) {
    stmt.run(uuid(), req.params.id, kpi.kpi_id, kpi.weight, kpi.target_value, kpi.slab_set_id || null);
  }

  res.json({ success: true });
});

// Update plan slabs
router.put('/:id/slabs', (req, res) => {
  const db = getDb();
  const { slab_sets } = req.body;
  const planId = req.params.id;

  // Delete existing slab tiers and sets for this plan
  const existingSets = db.prepare('SELECT id FROM slab_sets WHERE plan_id = ?').all(planId);
  for (const s of existingSets) {
    db.prepare('DELETE FROM slab_tiers WHERE slab_set_id = ?').run(s.id);
  }
  db.prepare('DELETE FROM slab_sets WHERE plan_id = ?').run(planId);

  // Insert new
  const setStmt = db.prepare('INSERT INTO slab_sets (id, name, type, plan_id, kpi_id) VALUES (?, ?, ?, ?, ?)');
  const tierStmt = db.prepare('INSERT INTO slab_tiers (id, slab_set_id, tier_order, min_percent, max_percent, rate, rate_type) VALUES (?, ?, ?, ?, ?, ?, ?)');

  for (const ss of (slab_sets || [])) {
    const ssId = uuid();
    setStmt.run(ssId, ss.name, ss.type || 'step', planId, ss.kpi_id || null);
    (ss.tiers || []).forEach((tier, i) => {
      tierStmt.run(uuid(), ssId, tier.tier_order ?? i + 1, tier.min_percent, tier.max_percent ?? null, tier.rate, tier.rate_type || 'percentage');
    });
  }

  res.json({ success: true });
});

// Update plan rules
router.put('/:id/rules', (req, res) => {
  const db = getDb();
  const { rule_sets } = req.body;
  const planId = req.params.id;

  const existingSets = db.prepare('SELECT id FROM rule_sets WHERE plan_id = ?').all(planId);
  for (const s of existingSets) {
    db.prepare('DELETE FROM rules WHERE rule_set_id = ?').run(s.id);
  }
  db.prepare('DELETE FROM rule_sets WHERE plan_id = ?').run(planId);

  const setStmt = db.prepare('INSERT INTO rule_sets (id, plan_id, name, description) VALUES (?, ?, ?, ?)');
  const ruleStmt = db.prepare('INSERT INTO rules (id, rule_set_id, dimension, rule_type, match_type, match_values, priority) VALUES (?, ?, ?, ?, ?, ?, ?)');

  for (const rs of (rule_sets || [])) {
    const rsId = uuid();
    setStmt.run(rsId, planId, rs.name, rs.description || null);
    (rs.rules || []).forEach((rule, i) => {
      ruleStmt.run(uuid(), rsId, rule.dimension, rule.rule_type, rule.match_type || 'exact', JSON.stringify(rule.match_values || []), rule.priority ?? i);
    });
  }

  res.json({ success: true });
});

// Update eligibility rules
router.put('/:id/eligibility', (req, res) => {
  const db = getDb();
  const { rules } = req.body;
  const planId = req.params.id;

  db.prepare('DELETE FROM eligibility_rules WHERE plan_id = ?').run(planId);
  const stmt = db.prepare('INSERT INTO eligibility_rules (id, plan_id, metric, operator, threshold, action, reduction_percent) VALUES (?, ?, ?, ?, ?, ?, ?)');
  for (const r of (rules || [])) {
    stmt.run(uuid(), planId, r.metric, r.operator || '>=', r.threshold, r.action || 'zero_payout', r.reduction_percent || 0);
  }

  res.json({ success: true });
});

// Update multiplier rules
router.put('/:id/multipliers', (req, res) => {
  const db = getDb();
  const { rules } = req.body;
  const planId = req.params.id;

  db.prepare('DELETE FROM multiplier_rules WHERE plan_id = ?').run(planId);
  const stmt = db.prepare('INSERT INTO multiplier_rules (id, plan_id, name, type, condition_metric, condition_operator, condition_value, multiplier_value, stacking_mode) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)');
  for (const r of (rules || [])) {
    stmt.run(uuid(), planId, r.name, r.type, r.condition_metric, r.condition_operator || '>=', r.condition_value, r.multiplier_value || 1.0, r.stacking_mode || 'multiplicative');
  }

  res.json({ success: true });
});

// Update penalty rules
router.put('/:id/penalties', (req, res) => {
  const db = getDb();
  const { rules } = req.body;
  const planId = req.params.id;

