                  </div>
                </div>
                <div className="text-right">
                  <div className="text-sm font-semibold text-slate-900">{formatCurrency(run.total_payout)}</div>
                  <div className="text-xs text-slate-500">{run.started_at}</div>
                </div>
              </button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

