function RulesTab({ plan, setPlan }) {
  const [saving, setSaving] = useState(false);
  const ruleSets = plan.rule_sets || [];

  const addRuleSet = () => {
    setPlan({...plan, rule_sets: [...ruleSets, { name: '', description: '', rules: [] }]});
  };

  const updateSet = (idx, field, value) => {
    const updated = [...ruleSets];
    updated[idx] = {...updated[idx], [field]: value};
    setPlan({...plan, rule_sets: updated});
  };

  const removeSet = (idx) => {
    setPlan({...plan, rule_sets: ruleSets.filter((_, i) => i !== idx)});
  };

  const addRule = (setIdx) => {
    const updated = [...ruleSets];
    const rules = [...(updated[setIdx].rules || [])];
    rules.push({ dimension: 'product_category', rule_type: 'include', match_type: 'exact', match_values: [] });
    updated[setIdx] = {...updated[setIdx], rules};
    setPlan({...plan, rule_sets: updated});
  };

  const updateRule = (setIdx, ruleIdx, field, value) => {
    const updated = [...ruleSets];
    const rules = [...updated[setIdx].rules];
    rules[ruleIdx] = {...rules[ruleIdx], [field]: value};
    updated[setIdx] = {...updated[setIdx], rules};
    setPlan({...plan, rule_sets: updated});
  };

  const removeRule = (setIdx, ruleIdx) => {
    const updated = [...ruleSets];
    updated[setIdx] = {...updated[setIdx], rules: updated[setIdx].rules.filter((_, i) => i !== ruleIdx)};
    setPlan({...plan, rule_sets: updated});
  };

  const handleSave = async () => {
    if (!plan.id) return toast.error('Save the General tab first');
    setSaving(true);
    try {
      const payload = ruleSets.map(rs => ({
        name: rs.name, description: rs.description,
        rules: (rs.rules || []).map(r => ({
          dimension: r.dimension, rule_type: r.rule_type, match_type: r.match_type,
          match_values: typeof r.match_values === 'string' ? JSON.parse(r.match_values) : r.match_values,
        })),
      }));
      await api.put(`/plans/${plan.id}/rules`, { rule_sets: payload });
      toast.success('Rules saved');
    } catch (err) {
      toast.error(err.message);
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h3 className="font-semibold text-slate-900">Include/Exclude Rules</h3>
          <p className="text-sm text-slate-500">Filter which products and customers count toward commission</p>
        </div>
        <button onClick={addRuleSet} className="btn-primary flex items-center gap-1 text-sm">
          <Plus className="w-4 h-4" /> Add Rule Set
        </button>
      </div>

      {ruleSets.map((rs, si) => (
        <div key={rs.id || si} className="border border-slate-200 rounded-lg p-4 space-y-4">
          <div className="flex items-start gap-4">
            <div className="flex-1">
              <label className="label">Set Name</label>
              <input className="input" value={rs.name} onChange={e => updateSet(si, 'name', e.target.value)} />
            </div>
            <div className="flex-1">
              <label className="label">Description</label>
              <input className="input" value={rs.description || ''} onChange={e => updateSet(si, 'description', e.target.value)} />
            </div>
            <button onClick={() => removeSet(si)} className="mt-7 p-1 hover:bg-rose-50 rounded">
              <Trash2 className="w-4 h-4 text-rose-400" />
            </button>
          </div>

          <div className="space-y-2">
            {(rs.rules || []).map((rule, ri) => {
              const values = typeof rule.match_values === 'string' ? JSON.parse(rule.match_values) : (rule.match_values || []);
              return (
                <div key={rule.id || ri} className="flex items-center gap-2 py-2 px-3 bg-slate-50 rounded-lg">
                  <select className="input w-28" value={rule.rule_type} onChange={e => updateRule(si, ri, 'rule_type', e.target.value)}>
                    <option value="include">Include</option>
                    <option value="exclude">Exclude</option>
                  </select>
                  <select className="input w-40" value={rule.dimension} onChange={e => updateRule(si, ri, 'dimension', e.target.value)}>
                    <option value="product">Product</option>
                    <option value="customer">Customer</option>
                    <option value="product_category">Product Category</option>
                    <option value="customer_channel">Customer Channel</option>
                  </select>
                  <select className="input w-24" value={rule.match_type} onChange={e => updateRule(si, ri, 'match_type', e.target.value)}>
                    <option value="exact">Exact</option>
                    <option value="category">Category</option>
                    <option value="tag">Tag</option>
                  </select>
                  <input className="input flex-1" value={values.join(', ')} placeholder="comma-separated values"
                    onChange={e => updateRule(si, ri, 'match_values', e.target.value.split(',').map(v => v.trim()).filter(Boolean))} />
                  <button onClick={() => removeRule(si, ri)} className="p-1 hover:bg-rose-50 rounded">
                    <Trash2 className="w-3.5 h-3.5 text-rose-400" />
                  </button>
                </div>
              );
            })}
          </div>
          <button onClick={() => addRule(si)} className="text-sm text-primary-600 hover:underline flex items-center gap-1"><Plus className="w-3.5 h-3.5" /> Add Rule</button>
        </div>
      ))}

      {ruleSets.length === 0 && (
        <div className="text-center py-8 text-slate-500">
          <Filter className="w-8 h-8 mx-auto mb-2 text-slate-300" />
          <p>No include/exclude rules configured</p>
        </div>
      )}

      <div className="pt-4 border-t border-slate-200">
        <button onClick={handleSave} disabled={saving} className="btn-primary flex items-center gap-2">
          <Save className="w-4 h-4" /> {saving ? 'Saving...' : 'Save Rules'}
        </button>
      </div>
    </div>
  );
}

