import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../api/client';
import toast from 'react-hot-toast';
import { cn, formatCurrency, getStatusColor, getStatusLabel } from '../lib/utils';
import {
  ArrowLeft, Settings, Target, BarChart3, Filter, ShieldCheck,
  Zap, AlertTriangle, ArrowUpDown, Scissors, Save, ChevronDown,
  Sparkles, AlertCircle
} from 'lucide-react';

const tabs = [
  { id: 'general', label: 'General', icon: Settings },
  { id: 'kpis', label: 'KPIs & Weights', icon: Target },
  { id: 'slabs', label: 'Slabs', icon: BarChart3 },
  { id: 'rules', label: 'Include/Exclude', icon: Filter },
  { id: 'eligibility', label: 'Eligibility', icon: ShieldCheck },
  { id: 'multipliers', label: 'Multipliers', icon: Zap },
  { id: 'penalties', label: 'Penalties', icon: AlertTriangle },
  { id: 'caps', label: 'Caps & Splits', icon: Scissors },
];

export default function PlanBuilderPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [plan, setPlan] = useState(null);
  const [activeTab, setActiveTab] = useState('general');
  const [loading, setLoading] = useState(!!id);
  const [allRoles, setAllRoles] = useState([]);
  const [allTerritories, setAllTerritories] = useState([]);
  const [allKpis, setAllKpis] = useState([]);

  useEffect(() => {
    const loads = [
      api.get('/roles'),
      api.get('/territories'),
      api.get('/kpis'),
    ];
    if (id && id !== 'new') loads.push(api.get(`/plans/${id}`));

    Promise.all(loads).then(([roles, territories, kpis, planData]) => {
      setAllRoles(roles);
      setAllTerritories(territories);
      setAllKpis(kpis);
      if (planData) setPlan(planData);
      else setPlan({
        name: '', description: '', status: 'draft', plan_type: 'monthly',
        effective_from: '2026-01-01', effective_to: '2026-12-31', base_payout: 15000,
        roles: [], territories: [], kpis: [], slab_sets: [], rule_sets: [],
        eligibility_rules: [], multiplier_rules: [], penalty_rules: [],
        capping_rules: [], split_rules: [],
      });
    }).catch(err => {
      toast.error('Failed to load plan data');
    }).finally(() => setLoading(false));
  }, [id]);

  if (loading || !plan) {
    return (
      <div className="space-y-6">
        <div className="h-8 w-64 bg-slate-200 rounded animate-pulse" />
        <div className="card p-8">
          <div className="h-96 bg-slate-100 rounded animate-pulse" />
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-4">
        <button onClick={() => navigate('/plans')} className="p-2 hover:bg-slate-100 rounded-lg transition-colors">
          <ArrowLeft className="w-5 h-5 text-slate-600" />
        </button>
        <div className="flex-1">
          <h1 className="text-2xl font-bold text-slate-900">
            {plan.id ? plan.name : 'New Commission Plan'}
          </h1>
          {plan.id && (
            <div className="flex items-center gap-3 mt-1">
              <span className={cn('badge', getStatusColor(plan.status))}>{getStatusLabel(plan.status)}</span>
              <span className="text-sm text-slate-500">{plan.plan_type}</span>
            </div>
          )}
        </div>
      </div>

      {/* Tab Navigation */}
      <div className="border-b border-slate-200">
        <div className="flex gap-1 overflow-x-auto pb-px">
          {tabs.map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={cn(
                'flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors whitespace-nowrap',
                activeTab === tab.id
                  ? 'border-primary-600 text-primary-600'
                  : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'
              )}
            >
              <tab.icon className="w-4 h-4" />
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* Tab Content */}
      <div className="card p-6">
        {activeTab === 'general' && <GeneralTab plan={plan} setPlan={setPlan} allRoles={allRoles} allTerritories={allTerritories} />}
        {activeTab === 'kpis' && <KpisTab plan={plan} setPlan={setPlan} allKpis={allKpis} />}
        {activeTab === 'slabs' && <SlabsTab plan={plan} />}
        {activeTab === 'rules' && <RulesTab plan={plan} />}
        {activeTab === 'eligibility' && <EligibilityTab plan={plan} />}
        {activeTab === 'multipliers' && <MultipliersTab plan={plan} />}
        {activeTab === 'penalties' && <PenaltiesTab plan={plan} />}
        {activeTab === 'caps' && <CapsTab plan={plan} />}
      </div>
    </div>
  );
}

// ====== TAB COMPONENTS ======

function GeneralTab({ plan, setPlan, allRoles, allTerritories }) {
  return (
    <div className="space-y-6 max-w-2xl">
      <div>
        <label className="label">Plan Name</label>
        <input className="input" value={plan.name} onChange={e => setPlan({...plan, name: e.target.value})} placeholder="e.g., Field Sales Monthly Incentive" />
      </div>
      <div>
        <label className="label">Description</label>
        <textarea className="input min-h-[80px]" value={plan.description || ''} onChange={e => setPlan({...plan, description: e.target.value})} placeholder="Describe the plan purpose..." />
      </div>
      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="label">Plan Type</label>
          <select className="input" value={plan.plan_type} onChange={e => setPlan({...plan, plan_type: e.target.value})}>
            <option value="monthly">Monthly</option>
            <option value="quarterly">Quarterly</option>
            <option value="annual">Annual</option>
          </select>
        </div>
        <div>
          <label className="label">Base Payout</label>
          <input type="number" className="input" value={plan.base_payout} onChange={e => setPlan({...plan, base_payout: Number(e.target.value)})} />
        </div>
      </div>
      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="label">Effective From</label>
          <input type="date" className="input" value={plan.effective_from} onChange={e => setPlan({...plan, effective_from: e.target.value})} />
        </div>
        <div>
          <label className="label">Effective To</label>
          <input type="date" className="input" value={plan.effective_to} onChange={e => setPlan({...plan, effective_to: e.target.value})} />
        </div>
      </div>
      <div>
        <label className="label">Status</label>
        <select className="input max-w-xs" value={plan.status} onChange={e => setPlan({...plan, status: e.target.value})}>
          <option value="draft">Draft</option>
          <option value="active">Active</option>
          <option value="expired">Expired</option>
          <option value="archived">Archived</option>
        </select>
      </div>

      {/* Applicable Roles */}
      <div>
        <label className="label">Applicable Roles</label>
        <div className="flex flex-wrap gap-2 mt-2">
          {allRoles.map(role => {
            const selected = plan.roles?.some(r => r.id === role.id);
            return (
              <button
                key={role.id}
                className={cn(
                  'px-3 py-1.5 rounded-lg text-sm font-medium border transition-colors',
                  selected ? 'bg-primary-50 border-primary-300 text-primary-700' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                )}
                onClick={() => {
                  const newRoles = selected
                    ? plan.roles.filter(r => r.id !== role.id)
                    : [...(plan.roles || []), role];
                  setPlan({...plan, roles: newRoles});
                }}
              >
                {role.name}
              </button>
            );
          })}
        </div>
      </div>

      {/* Territories */}
      <div>
        <label className="label">Territories</label>
        <div className="flex flex-wrap gap-2 mt-2">
          {allTerritories.map(terr => {
            const selected = plan.territories?.some(t => t.id === terr.id);
            return (
              <button
                key={terr.id}
                className={cn(
                  'px-3 py-1.5 rounded-lg text-sm font-medium border transition-colors',
                  selected ? 'bg-emerald-50 border-emerald-300 text-emerald-700' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                )}
                onClick={() => {
                  const newTerrs = selected
                    ? plan.territories.filter(t => t.id !== terr.id)
                    : [...(plan.territories || []), terr];
                  setPlan({...plan, territories: newTerrs});
                }}
              >
                {terr.name}
                <span className="ml-1 text-xs opacity-60">({terr.type})</span>
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
}

function KpisTab({ plan, allKpis }) {
  const planKpis = plan.kpis || [];
  const totalWeight = planKpis.reduce((s, k) => s + (k.weight || 0), 0);

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <div>
          <h3 className="font-semibold text-slate-900">KPI Configuration</h3>
          <p className="text-sm text-slate-500">Assign KPIs, set targets, and allocate weights (must sum to 100%)</p>
        </div>
        <div className={cn('badge', totalWeight === 100 ? 'badge-success' : 'badge-warning')}>
          Total Weight: {totalWeight}%
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-sm">
          <thead>
            <tr className="border-b border-slate-200">
              <th className="text-left py-3 px-4 font-medium text-slate-600">KPI</th>
              <th className="text-left py-3 px-4 font-medium text-slate-600">Category</th>
              <th className="text-right py-3 px-4 font-medium text-slate-600">Target</th>
              <th className="text-right py-3 px-4 font-medium text-slate-600">Weight %</th>
              <th className="text-left py-3 px-4 font-medium text-slate-600">Slab</th>
            </tr>
          </thead>
          <tbody>
            {planKpis.map((pk, i) => (
              <tr key={pk.kpi_id || i} className="border-b border-slate-100 hover:bg-slate-50">
                <td className="py-3 px-4">
                  <div className="font-medium text-slate-900">{pk.kpi_name}</div>
                  <div className="text-xs text-slate-400">{pk.kpi_code}</div>
                </td>
                <td className="py-3 px-4">
                  <span className="badge badge-gray">{pk.kpi_category}</span>
                </td>
                <td className="py-3 px-4 text-right font-mono">
                  {pk.unit === 'currency' ? formatCurrency(pk.target_value) : `${pk.target_value}${pk.unit === 'percentage' ? '%' : ''}`}
                </td>
                <td className="py-3 px-4 text-right">
                  <div className="flex items-center justify-end gap-2">
                    <div className="w-16 h-2 bg-slate-200 rounded-full overflow-hidden">
                      <div className="h-full bg-primary-500 rounded-full" style={{ width: `${pk.weight}%` }} />
                    </div>
                    <span className="font-semibold text-slate-900 w-10 text-right">{pk.weight}%</span>
                  </div>
                </td>
                <td className="py-3 px-4">
                  {pk.slab_set_id ? (
                    <span className="badge badge-info">Configured</span>
                  ) : (
                    <span className="badge badge-gray">Linear</span>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {planKpis.length === 0 && (
        <div className="text-center py-8 text-slate-500">
          <Target className="w-8 h-8 mx-auto mb-2 text-slate-300" />
          <p>No KPIs configured for this plan</p>
        </div>
      )}
    </div>
  );
}

function SlabsTab({ plan }) {
  const slabSets = plan.slab_sets || [];

  return (
    <div className="space-y-6">
      <div>
        <h3 className="font-semibold text-slate-900">Slab Configuration</h3>
        <p className="text-sm text-slate-500">Define payout rates at different achievement levels</p>
      </div>

      {slabSets.map(slab => (
        <div key={slab.id} className="border border-slate-200 rounded-lg p-4">
          <div className="flex items-center justify-between mb-3">
            <div>
              <h4 className="font-medium text-slate-900">{slab.name}</h4>
              <span className={cn('badge', slab.type === 'step' ? 'badge-info' : slab.type === 'progressive' ? 'badge-success' : 'badge-warning')}>
                {slab.type.charAt(0).toUpperCase() + slab.type.slice(1)}
              </span>
            </div>
          </div>

          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-slate-200">
                <th className="text-left py-2 px-3 font-medium text-slate-600">Tier</th>
                <th className="text-left py-2 px-3 font-medium text-slate-600">Achievement Range</th>
                <th className="text-right py-2 px-3 font-medium text-slate-600">Rate</th>
                <th className="text-left py-2 px-3 font-medium text-slate-600">Type</th>
              </tr>
            </thead>
            <tbody>
              {(slab.tiers || []).map(tier => (
                <tr key={tier.id} className="border-b border-slate-100">
                  <td className="py-2 px-3 text-slate-600">{tier.tier_order}</td>
                  <td className="py-2 px-3">
                    <span className="font-mono text-slate-900">
                      {tier.min_percent}% — {tier.max_percent !== null ? `${tier.max_percent}%` : '∞'}
                    </span>
                  </td>
                  <td className="py-2 px-3 text-right font-semibold text-slate-900">{tier.rate}{tier.rate_type === 'percentage' ? '%' : ''}</td>
                  <td className="py-2 px-3 text-slate-500">{tier.rate_type}</td>
                </tr>
              ))}
            </tbody>
          </table>

          {/* Visual slab preview */}
          <div className="mt-3 flex gap-0.5 h-8">
            {(slab.tiers || []).map((tier, i) => {
              const width = tier.max_percent !== null ? (tier.max_percent - tier.min_percent) : 30;
              const colors = ['bg-slate-200', 'bg-blue-200', 'bg-emerald-200', 'bg-amber-200', 'bg-rose-200'];
              return (
                <div
                  key={tier.id}
                  className={cn('rounded flex items-center justify-center text-xs font-medium', colors[i % colors.length])}
                  style={{ flex: width }}
                  title={`${tier.min_percent}%-${tier.max_percent ?? '∞'}: ${tier.rate}${tier.rate_type === 'percentage' ? '%' : ''}`}
                >
                  {tier.rate}{tier.rate_type === 'percentage' ? '%' : ''}
                </div>
              );
            })}
          </div>
        </div>
      ))}

      {slabSets.length === 0 && (
        <div className="text-center py-8 text-slate-500">
          <BarChart3 className="w-8 h-8 mx-auto mb-2 text-slate-300" />
          <p>No slab configurations</p>
        </div>
      )}

      <ComingSoonSection items={['Decelerator slabs (reverse rate above cap)', 'Custom slab formulas']} />
    </div>
  );
}

function RulesTab({ plan }) {
  const ruleSets = plan.rule_sets || [];

  return (
    <div className="space-y-6">
      <div>
        <h3 className="font-semibold text-slate-900">Include/Exclude Rules</h3>
        <p className="text-sm text-slate-500">Filter which products and customers count toward commission. Exclusions override inclusions.</p>
      </div>

      {ruleSets.map(rs => (
        <div key={rs.id} className="border border-slate-200 rounded-lg p-4">
          <h4 className="font-medium text-slate-900 mb-3">{rs.name}</h4>
          {rs.description && <p className="text-sm text-slate-500 mb-3">{rs.description}</p>}

          <div className="space-y-2">
            {(rs.rules || []).map(rule => {
              const values = typeof rule.match_values === 'string' ? JSON.parse(rule.match_values) : rule.match_values;
              return (
                <div key={rule.id} className="flex items-center gap-3 py-2 px-3 bg-slate-50 rounded-lg">
                  <span className={cn('badge', rule.rule_type === 'include' ? 'badge-success' : 'badge-danger')}>
                    {rule.rule_type.toUpperCase()}
                  </span>
                  <span className="text-sm text-slate-600">{rule.dimension.replace('_', ' ')}</span>
                  <span className="text-sm text-slate-400">({rule.match_type})</span>
                  <div className="flex flex-wrap gap-1">
                    {values.map(v => (
                      <span key={v} className="badge badge-gray text-xs">{v}</span>
                    ))}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      ))}

      {ruleSets.length === 0 && (
        <div className="text-center py-8 text-slate-500">
          <Filter className="w-8 h-8 mx-auto mb-2 text-slate-300" />
          <p>No include/exclude rules configured</p>
        </div>
      )}

      <ComingSoonSection items={['Geography / Org-level dimensions', 'Transaction-type dimensions', 'IF-THEN-EXCEPT conditional rules']} />
    </div>
  );
}

function EligibilityTab({ plan }) {
  const rules = plan.eligibility_rules || [];

  return (
    <div className="space-y-6">
      <div>
        <h3 className="font-semibold text-slate-900">Eligibility Rules</h3>
        <p className="text-sm text-slate-500">Minimum criteria employees must meet to receive payouts</p>
      </div>

      <div className="space-y-3">
        {rules.map(rule => (
          <div key={rule.id} className="flex items-center gap-4 py-3 px-4 border border-slate-200 rounded-lg">
            <ShieldCheck className={cn('w-5 h-5 flex-shrink-0', rule.is_active ? 'text-emerald-500' : 'text-slate-300')} />
            <div className="flex-1">
              <div className="text-sm font-medium text-slate-900">
                {rule.metric.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase())} {rule.operator} {rule.threshold}{rule.metric.includes('percent') ? '%' : ''}
              </div>
              <div className="text-xs text-slate-500">
                Action: <span className={cn(
                  'font-medium',
                  rule.action === 'zero_payout' ? 'text-rose-600' : rule.action === 'reduce_percent' ? 'text-amber-600' : 'text-slate-600'
                )}>
                  {rule.action === 'zero_payout' ? 'Zero Payout' : rule.action === 'reduce_percent' ? `Reduce by ${rule.reduction_percent}%` : 'Warning Only'}
                </span>
              </div>
            </div>
            <span className={cn('badge', rule.is_active ? 'badge-success' : 'badge-gray')}>
              {rule.is_active ? 'Active' : 'Inactive'}
            </span>
          </div>
        ))}
      </div>

      {rules.length === 0 && (
        <div className="text-center py-8 text-slate-500">
          <ShieldCheck className="w-8 h-8 mx-auto mb-2 text-slate-300" />
          <p>No eligibility rules configured</p>
        </div>
      )}

      <ComingSoonSection items={['Min active days', 'Min lines sold', 'Custom eligibility formulas']} />
    </div>
  );
}

function MultipliersTab({ plan }) {
  const rules = plan.multiplier_rules || [];

  return (
    <div className="space-y-6">
      <div>
        <h3 className="font-semibold text-slate-900">Multiplier Rules</h3>
        <p className="text-sm text-slate-500">Bonus multipliers for exceeding specific conditions</p>
      </div>

      <div className="space-y-3">
        {rules.map(rule => (
          <div key={rule.id} className="flex items-center gap-4 py-3 px-4 border border-slate-200 rounded-lg">
            <Zap className={cn('w-5 h-5 flex-shrink-0', rule.is_active ? 'text-amber-500' : 'text-slate-300')} />
            <div className="flex-1">
              <div className="text-sm font-medium text-slate-900">{rule.name}</div>
              <div className="text-xs text-slate-500">
                {rule.condition_metric.replace(/_/g, ' ')} {rule.condition_operator} {rule.condition_value}
                <span className="mx-2">→</span>
                <span className="font-semibold text-primary-600">{rule.multiplier_value}x</span>
                <span className="ml-2 text-slate-400">({rule.stacking_mode})</span>
              </div>
            </div>
            <span className={cn('badge', {
              'badge-info': rule.type === 'growth',
              'badge-success': rule.type === 'strategic_sku',
              'badge-warning': rule.type === 'new_launch',
            }[rule.type] || 'badge-gray')}>
              {rule.type.replace(/_/g, ' ')}
            </span>
          </div>
        ))}
      </div>

      {rules.length === 0 && (
        <div className="text-center py-8 text-slate-500">
          <Zap className="w-8 h-8 mx-auto mb-2 text-slate-300" />
          <p>No multiplier rules configured</p>
        </div>
      )}

      <ComingSoonSection items={['New launch multipliers', 'Channel mix multipliers', 'Collection speed multipliers']} />
    </div>
  );
}

function PenaltiesTab({ plan }) {
  const rules = plan.penalty_rules || [];

  return (
    <div className="space-y-6">
      <div>
        <h3 className="font-semibold text-slate-900">Penalty Rules</h3>
        <p className="text-sm text-slate-500">Deductions triggered when thresholds are exceeded</p>
      </div>

      <div className="space-y-3">
        {rules.map(rule => (
          <div key={rule.id} className="flex items-center gap-4 py-3 px-4 border border-slate-200 rounded-lg">
            <AlertTriangle className={cn('w-5 h-5 flex-shrink-0', rule.is_active ? 'text-rose-500' : 'text-slate-300')} />
            <div className="flex-1">
              <div className="text-sm font-medium text-slate-900">{rule.name}</div>
              <div className="text-xs text-slate-500">
                {rule.trigger_metric.replace(/_/g, ' ')} {rule.trigger_operator} {rule.trigger_value}
                <span className="mx-2">→</span>
                <span className="font-semibold text-rose-600">-{rule.penalty_value}{rule.penalty_type === 'percentage' ? '%' : ''}</span>
              </div>
            </div>
          </div>
        ))}
      </div>

      {rules.length === 0 && (
        <div className="text-center py-8 text-slate-500">
          <AlertTriangle className="w-8 h-8 mx-auto mb-2 text-slate-300" />
          <p>No penalty rules configured</p>
        </div>
      )}

      <ComingSoonSection items={['Slab downgrade penalties', 'Fixed amount penalties', 'Credit note penalties']} />
    </div>
  );
}

function CapsTab({ plan }) {
  const caps = plan.capping_rules || [];
  const splits = plan.split_rules || [];

  return (
    <div className="space-y-8">
      {/* Caps */}
      <div className="space-y-4">
        <div>
          <h3 className="font-semibold text-slate-900">Capping Rules</h3>
          <p className="text-sm text-slate-500">Maximum payout limits (most restrictive wins)</p>
        </div>

        <div className="space-y-3">
          {caps.map(cap => (
            <div key={cap.id} className="flex items-center gap-4 py-3 px-4 border border-slate-200 rounded-lg">
              <ArrowUpDown className="w-5 h-5 text-blue-500 flex-shrink-0" />
              <div className="flex-1">
                <div className="text-sm font-medium text-slate-900">
                  {cap.cap_type === 'max_per_plan' ? 'Maximum Per Plan' :
                   cap.cap_type === 'percent_of_salary' ? '% of Base Salary' : 'Maximum Per KPI'}
                </div>
                <div className="text-xs text-slate-500">
                  Limit: <span className="font-semibold text-slate-900">
                    {cap.cap_type === 'max_per_plan' ? formatCurrency(cap.cap_value) :
                     cap.cap_type === 'percent_of_salary' ? `${cap.cap_value}%` : formatCurrency(cap.cap_value)}
                  </span>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Splits */}
      <div className="space-y-4">
        <div>
          <h3 className="font-semibold text-slate-900">Split Rules</h3>
          <p className="text-sm text-slate-500">Commission split between roles</p>
        </div>

        <div className="space-y-3">
          {splits.map(split => (
            <div key={split.id} className="border border-slate-200 rounded-lg p-4">
              <h4 className="font-medium text-slate-900 mb-3">{split.name}</h4>
              <div className="flex gap-2">
                {(split.participants || []).map(p => (
                  <div key={p.id} className="flex-1 bg-slate-50 rounded-lg p-3 text-center">
                    <div className="text-2xl font-bold text-primary-600">{p.split_percent}%</div>
                    <div className="text-sm text-slate-600">{p.role_name}</div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>

        {splits.length === 0 && caps.length === 0 && (
          <div className="text-center py-8 text-slate-500">
            <Scissors className="w-8 h-8 mx-auto mb-2 text-slate-300" />
            <p>No caps or splits configured</p>
          </div>
        )}

        <ComingSoonSection items={['Budget / regional caps', 'Max per KPI caps', 'Pool distribution splits', 'Shared credit splits']} />
      </div>
    </div>
  );
}

function ComingSoonSection({ items }) {
  return (
    <div className="mt-6 pt-6 border-t border-dashed border-slate-200">
      <div className="flex items-center gap-2 mb-3">
        <Sparkles className="w-4 h-4 text-violet-500" />
        <span className="text-sm font-medium text-slate-500">Coming Soon</span>
      </div>
      <div className="flex flex-wrap gap-2">
        {items.map(item => (
          <span key={item} className="badge badge-coming-soon text-xs">
            {item}
          </span>
        ))}
      </div>
    </div>
  );
}

