 1→export function applyMappingFilters(db, transactions, ruleSets) {
 2→  if (!ruleSets || ruleSets.length === 0) return transactions;
 3→  
 4→  return transactions.filter(txn => {
 5→    let included = true;
 6→    let excluded = false;
 7→    
 8→    for (const ruleSet of ruleSets) {
 9→      for (const rule of ruleSet.rules || []) {
10→        const matchValues = typeof rule.match_values === 'string' ? JSON.parse(rule.match_values) : rule.match_values;
11→        let matches = false;
12→        
13→        switch (rule.dimension) {
14→          case 'product':
15→            matches = matchValues.includes(txn.product_id);
16→            break;
17→          case 'customer':
18→            matches = matchValues.includes(txn.customer_id);
19→            break;
20→          case 'product_category':
21→            matches = matchValues.includes(txn.product_category);
22→            break;
23→          case 'customer_channel':
24→            matches = matchValues.includes(txn.customer_channel);
25→            break;
26→        }
27→        
28→        if (rule.rule_type === 'include' && !matches) {
29→          included = false;
30→        }
31→        if (rule.rule_type === 'exclude' && matches) {
32→          excluded = true; // Exclusion overrides inclusion
33→        }
34→      }
35→    }
36→    
37→    return included && !excluded;
38→  });
39→}
