 1→import { clsx } from 'clsx';
 2→import { twMerge } from 'tailwind-merge';
 3→
 4→export function cn(...inputs) {
 5→  return twMerge(clsx(inputs));
 6→}
 7→
 8→export function formatCurrency(amount) {
 9→  return new Intl.NumberFormat('en-AE', {
10→    style: 'currency',
11→    currency: 'AED',
12→    minimumFractionDigits: 0,
13→    maximumFractionDigits: 0,
14→  }).format(amount);
15→}
16→
17→export function formatPercent(value, decimals = 1) {
18→  return `${Number(value).toFixed(decimals)}%`;
19→}
20→
21→export function formatNumber(num) {
22→  return new Intl.NumberFormat('en-AE').format(num);
23→}
24→
25→export function getStatusColor(status) {
26→  const colors = {
27→    draft: 'badge-gray',
28→    active: 'badge-success',
29→    expired: 'badge-danger',
30→    archived: 'badge-gray',
31→    pending: 'badge-warning',
32→    submitted: 'badge-info',
33→    manager_approved: 'badge-info',
34→    finance_approved: 'badge-info',
35→    hr_approved: 'badge-success',
36→    rejected: 'badge-danger',
37→    locked: 'badge-success',
38→    running: 'badge-warning',
39→    completed: 'badge-success',
40→    failed: 'badge-danger',
41→  };
42→  return colors[status] || 'badge-gray';
43→}
44→
45→export function getStatusLabel(status) {
46→  return status?.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase()) || '';
47→}
