 41→
 42→  useEffect(() => {
 43→    Promise.all([api.get('/plans'), api.get('/calculation/runs'), api.get('/employees')])
 44→      .then(([p, r, e]) => {
 45→        setPlans(p.filter(pl => pl.status === 'active'));
 46→        setPastRuns(r);
 47→        setEmployees(e);
 48→        if (p.length > 0) setSelectedPlan(p[0].id);
 49→      })
 50→      .finally(() => setLoading(false));
 51→  }, []);
 52→
 53→  const runCalculation = async () => {
 54→    if (!selectedPlan) return toast.error('Select a plan first');
 55→    setRunning(true);
 56→    setResult(null);
 57→    setCurrentStep(0);
 58→
 59→    // Animate steps
 60→    const stepAnimation = setInterval(() => {
 61→      setCurrentStep(prev => {
