  1→export function calculateKpiAchievement(transactions, planKpi, employee, period, db) {
  2→  const sales = transactions.filter(t => t.transaction_type === 'sale');
  3→  const returns = transactions.filter(t => t.transaction_type === 'return');
  4→  const collections = transactions.filter(t => t.transaction_type === 'collection');
  5→  
  6→  let actual = 0;
  7→  const target = planKpi.target_value;
  8→  
  9→  switch (planKpi.kpi_code) {
 10→    case 'TOTAL_REVENUE':
 11→      actual = sales.reduce((sum, t) => sum + t.amount, 0);
 12→      break;
 13→      
 14→    case 'REVENUE_GROWTH': {
 15→      const currentRev = sales.reduce((sum, t) => sum + t.amount, 0);
 16→      // Get previous period revenue
 17→      const [year, month] = period.split('-').map(Number);
 18→      const prevPeriod = `${year - 1}-${String(month).padStart(2, '0')}`;
 19→      const prevRevRow = db.prepare(`
 20→        SELECT COALESCE(SUM(amount), 0) as prev
 21→        FROM transactions WHERE employee_id = ? AND period = ? AND transaction_type = 'sale'
 22→      `).get(employee.id, prevPeriod);
 23→      const prevRev = prevRevRow.prev;
 24→      actual = prevRev > 0 ? ((currentRev - prevRev) / prevRev) * 100 : 0;
 25→      break;
 26→    }
 27→      
 28→    case 'UNITS_SOLD':
 29→      actual = sales.reduce((sum, t) => sum + t.quantity, 0);
 30→      break;
 31→      
 32→    case 'OUTLET_COVERAGE':
 33→      actual = new Set(sales.map(t => t.customer_id)).size;
 34→      break;
 35→      
 36→    case 'LINES_PER_CALL': {
 37→      const uniqueProducts = new Set(sales.map(t => t.product_id)).size;
 38→      const uniqueCustomers = new Set(sales.map(t => t.customer_id)).size;
 39→      actual = uniqueCustomers > 0 ? uniqueProducts / uniqueCustomers : 0;
 40→      break;
 41→    }
 42→      
 43→    case 'COLLECTION_PERCENT': {
 44→      const totalSales = sales.reduce((sum, t) => sum + t.amount, 0);
 45→      const totalCollections = collections.reduce((sum, t) => sum + t.amount, 0);
 46→      actual = totalSales > 0 ? (totalCollections / totalSales) * 100 : 0;
 47→      break;
 48→    }
 49→      
 50→    case 'RETURN_PERCENT': {
 51→      const totalSalesAmt = sales.reduce((sum, t) => sum + t.amount, 0);
 52→      const totalReturns = returns.reduce((sum, t) => sum + t.amount, 0);
 53→      actual = totalSalesAmt > 0 ? (totalReturns / totalSalesAmt) * 100 : 0;
 54→      break;
 55→    }
 56→      
 57→    case 'STRATEGIC_SKU_REV':
 58→      actual = sales.filter(t => t.is_strategic).reduce((sum, t) => sum + t.amount, 0);
 59→      break;
 60→      
 61→    case 'NEW_LAUNCH_SALES':
 62→      actual = sales.filter(t => t.is_new_launch).reduce((sum, t) => sum + t.amount, 0);
 63→      break;
 64→      
 65→    case 'NEW_CUSTOMERS':
 66→      // Simplified: count distinct customers
 67→      actual = new Set(sales.map(t => t.customer_id)).size;
 68→      break;
 69→      
 70→    case 'TEAM_REVENUE': {
 71→      // Sum of direct reports' revenue
 72→      const reports = db.prepare('SELECT id FROM employees WHERE reports_to = ?').all(employee.id);
 73→      let teamRev = 0;
 74→      for (const rep of reports) {
 75→        const repRev = db.prepare(`
 76→          SELECT COALESCE(SUM(amount), 0) as rev
 77→          FROM transactions WHERE employee_id = ? AND period = ? AND transaction_type = 'sale'
 78→        `).get(rep.id, period);
 79→        teamRev += repRev.rev;
 80→      }
 81→      actual = teamRev;
 82→      break;
 83→    }
 84→      
 85→    case 'TEAM_TARGET_ACH':
 86→      // Simplified: return achievement % based on actual team target
 87→      actual = 90; // Default for prototype
 88→      break;
 89→      
 90→    case 'REV_PER_OUTLET': {
 91→      const revTotal = sales.reduce((sum, t) => sum + t.amount, 0);
 92→      const outlets = new Set(sales.map(t => t.customer_id)).size;
 93→      actual = outlets > 0 ? revTotal / outlets : 0;
 94→      break;
 95→    }
 96→      
 97→    case 'OTD_PERCENT':
 98→      actual = 92; // Default for prototype
 99→      break;
100→      
101→    case 'GROSS_MARGIN':
102→      actual = 28; // Default for prototype
103→      break;
104→      
105→    default:
106→      actual = 0;
107→  }
108→  
109→  // For lower_is_better KPIs (like return %), invert the achievement
110→  let percent;
111→  if (planKpi.direction === 'lower_is_better') {
112→    percent = target > 0 ? Math.max(0, (2 * target - actual) / target * 100) : 0;
113→  } else {
114→    percent = target > 0 ? (actual / target) * 100 : 0;
115→  }
116→  
117→  return {
118→    actual: Math.round(actual * 100) / 100,
119→    target,
120→    percent: Math.round(percent * 100) / 100,
121→  };
122→}
