 5→const router = Router();
 6→
 7→router.get('/', (req, res) => {
 8→  const db = getDb();
 9→  let query = 'SELECT * FROM kpi_definitions WHERE is_active = 1';
10→  const params = [];
11→  
12→  if (req.query.category) {
13→    query += ' AND category = ?';
14→    params.push(req.query.category);
15→  }
16→  
17→  query += ' ORDER BY category, name';
18→  const kpis = db.prepare(query).all(...params);
19→  res.json(kpis);
20→});
