22→router.get('/categories', (req, res) => {
23→  const db = getDb();
24→  const categories = db.prepare('SELECT DISTINCT category FROM kpi_definitions ORDER BY category').all();
25→  res.json(categories.map(c => c.category));
26→});
27→
28→router.get('/:id', (req, res) => {
29→  const db = getDb();
30→  const kpi = db.prepare('SELECT * FROM kpi_definitions WHERE id = ?').get(req.params.id);
31→  if (!kpi) return res.status(404).json({ error: 'KPI not found' });
32→  res.json(kpi);
33→});
34→
35→router.post('/', (req, res) => {
36→  const db = getDb();
37→  const id = uuid();
38→  const { name, code, category, description, formula, unit, direction, applicable_roles } = req.body;
39→
40→  db.prepare(`
41→    INSERT INTO kpi_definitions (id, name, code, category, description, formula, unit, direction, applicable_roles)
42→    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
43→  `).run(id, name, code, category, description, formula, unit || 'currency', direction || 'higher_is_better', JSON.stringify(applicable_roles || []));
44→
45→  const kpi = db.prepare('SELECT * FROM kpi_definitions WHERE id = ?').get(id);
46→  res.status(201).json(kpi);
47→});
48→
49→router.put('/:id', (req, res) => {
50→  const db = getDb();
51→  const kpi = db.prepare('SELECT * FROM kpi_definitions WHERE id = ?').get(req.params.id);
52→  if (!kpi) return res.status(404).json({ error: 'KPI not found' });
53→
54→  const { name, code, category, description, formula, unit, direction, applicable_roles } = req.body;
55→  db.prepare(`
56→    UPDATE kpi_definitions SET
57→      name = COALESCE(?, name),
58→      code = COALESCE(?, code),
59→      category = COALESCE(?, category),
60→      description = COALESCE(?, description),
61→      formula = COALESCE(?, formula),
62→      unit = COALESCE(?, unit),
63→      direction = COALESCE(?, direction),
64→      applicable_roles = COALESCE(?, applicable_roles)
65→    WHERE id = ?
66→  `).run(name, code, category, description, formula, unit, direction, applicable_roles != null ? JSON.stringify(applicable_roles) : null, req.params.id);
67→
68→  const updated = db.prepare('SELECT * FROM kpi_definitions WHERE id = ?').get(req.params.id);
69→  res.json(updated);
70→});
71→
72→router.delete('/:id', (req, res) => {
73→  const db = getDb();
74→  const kpi = db.prepare('SELECT * FROM kpi_definitions WHERE id = ?').get(req.params.id);
75→  if (!kpi) return res.status(404).json({ error: 'KPI not found' });
76→
77→  db.prepare('UPDATE kpi_definitions SET is_active = 0 WHERE id = ?').run(req.params.id);
78→  res.json({ success: true });
79→});
80→
81→export default router;
