  1→import { getDb } from '../db/database.js';
  2→import { v4 as uuid } from 'uuid';
  3→import { fetchScopedTransactions } from './step01_fetchTransactions.js';
  4→import { applyMappingFilters } from './step02_mappingFilters.js';
  5→import { calculateKpiAchievement } from './step03_kpiAchievement.js';
  6→import { determineSlab } from './step04_determineSlab.js';
  7→import { calculateKpiPayout } from './step05_kpiPayout.js';
  8→import { applyWeight } from './step06_applyWeight.js';
  9→import { aggregateKpis } from './step07_aggregateKpis.js';
 10→import { applyMultiplier } from './step08_applyMultiplier.js';
 11→import { applyPenalty } from './step09_applyPenalty.js';
 12→import { applyCap } from './step10_applyCap.js';
 13→import { storePayout } from './step11_storePayout.js';
 14→import { createApproval } from './step12_createApproval.js';
 15→import { checkEligibility } from './eligibilityEngine.js';
 16→
 17→export function runCalculationPipeline({ plan_id, period, created_by, is_simulation = false, overrides = {}, employee_id = null }) {
 18→  const db = getDb();
 19→  const startTime = Date.now();
 20→  
 21→  // Load plan configuration
 22→  const plan = db.prepare('SELECT * FROM commission_plans WHERE id = ?').get(plan_id);
 23→  if (!plan) throw new Error('Plan not found');
 24→  
 25→  // Create calculation run
 26→  const runId = uuid();
 27→  db.prepare(`
 28→    INSERT INTO calculation_runs (id, plan_id, period, status, is_simulation, simulation_params, created_by)
 29→    VALUES (?, ?, ?, 'running', ?, ?, ?)
 30→  `).run(runId, plan_id, period, is_simulation ? 1 : 0, JSON.stringify(overrides), created_by);
 31→  
 32→  const steps = [];
 33→  const log = (stepNum, name, detail) => {
 34→    steps.push({ step: stepNum, name, ...detail, timestamp: Date.now() - startTime });
 35→  };
 36→  
 37→  try {
 38→    // Get eligible employees for this plan
 39→    const planRoles = db.prepare('SELECT role_id FROM plan_roles WHERE plan_id = ?').all(plan_id).map(r => r.role_id);
 40→    const planTerritories = db.prepare('SELECT territory_id FROM plan_territories WHERE plan_id = ?').all(plan_id).map(t => t.territory_id);
 41→    
 42→    const employees = db.prepare(`
 43→      SELECT e.*, r.name as role_name FROM employees e
 44→      JOIN roles r ON e.role_id = r.id
 45→      WHERE e.is_active = 1 AND e.role_id IN (${planRoles.map(() => '?').join(',')})
 46→    `).all(...planRoles);
 47→    
 48→    // Filter by territory if specified
 49→    let filteredEmployees = planTerritories.length > 0
 50→      ? employees.filter(e => planTerritories.includes(e.territory_id))
 51→      : employees;
 52→
 53→    // Filter to single employee if specified
 54→    if (employee_id) {
 55→      filteredEmployees = filteredEmployees.filter(e => e.id === employee_id);
 56→    }
 57→    
 58→    log(0, 'Initialize', { employee_count: filteredEmployees.length, plan: plan.name });
 59→    
 60→    // Load plan KPIs
 61→    const planKpis = db.prepare(`
 62→      SELECT pk.*, k.name as kpi_name, k.code as kpi_code, k.formula, k.unit, k.direction, k.category as kpi_category
 63→      FROM plan_kpis pk JOIN kpi_definitions k ON pk.kpi_id = k.id
 64→      WHERE pk.plan_id = ?
 65→    `).all(plan_id);
 66→    
 67→    // Load rules
 68→    const ruleSets = db.prepare('SELECT * FROM rule_sets WHERE plan_id = ?').all(plan_id);
 69→    for (const rs of ruleSets) {
 70→      rs.rules = db.prepare('SELECT * FROM rules WHERE rule_set_id = ?').all(rs.id);
 71→    }
 72→    const eligibilityRules = db.prepare('SELECT * FROM eligibility_rules WHERE plan_id = ? AND is_active = 1').all(plan_id);
 73→    const multiplierRules = db.prepare('SELECT * FROM multiplier_rules WHERE plan_id = ? AND is_active = 1').all(plan_id);
 74→    const penaltyRules = db.prepare('SELECT * FROM penalty_rules WHERE plan_id = ? AND is_active = 1').all(plan_id);
 75→    const cappingRules = db.prepare('SELECT * FROM capping_rules WHERE plan_id = ? AND is_active = 1').all(plan_id);
 76→    const splitRules = db.prepare('SELECT * FROM split_rules WHERE plan_id = ? AND is_active = 1').all(plan_id);
 77→    for (const sr of splitRules) {
 78→      sr.participants = db.prepare('SELECT * FROM split_participants WHERE split_rule_id = ?').all(sr.id);
 79→    }
 80→    
 81→    // Load slab config
 82→    const slabSets = {};
 83→    for (const pk of planKpis) {
 84→      if (pk.slab_set_id) {
 85→        const ss = db.prepare('SELECT * FROM slab_sets WHERE id = ?').get(pk.slab_set_id);
 86→        if (ss) {
 87→          ss.tiers = db.prepare('SELECT * FROM slab_tiers WHERE slab_set_id = ? ORDER BY tier_order').all(ss.id);
 88→          slabSets[pk.kpi_id] = ss;
 89→        }
 90→      }
 91→    }
 92→    
 93→    const allPayouts = [];
 94→    
 95→    for (const employee of filteredEmployees) {
 96→      const empContext = {
 97→        employee,
 98→        plan,
 99→        period,
100→        overrides,
101→        basePayout: overrides.base_payout ?? plan.base_payout,
102→      };
103→      
104→      // Step 1: Fetch scoped transactions
105→      const transactions = fetchScopedTransactions(db, employee.id, period, employee.territory_id);
106→      log(1, 'Fetch Transactions', { employee: employee.name, count: transactions.length });
107→      
108→      // Step 2: Apply mapping filters (include/exclude)
109→      const filtered = applyMappingFilters(db, transactions, ruleSets);
110→      log(2, 'Apply Mapping Filters', { employee: employee.name, before: transactions.length, after: filtered.length });
111→      
112→      // Eligibility check (runs after step 2, needs transaction data)
113→      const eligibility = checkEligibility(filtered, eligibilityRules, empContext);
114→      log(2.5, 'Eligibility Check', { employee: employee.name, status: eligibility.status, details: eligibility.details });
115→      
116→      const kpiResults = [];
117→      
118→      for (const planKpi of planKpis) {
119→        const targetValue = overrides.targets?.[planKpi.kpi_id] ?? planKpi.target_value;
120→        
121→        // Step 3: Calculate KPI achievement
122→        const achievement = calculateKpiAchievement(filtered, planKpi, employee, period, db);
123→        log(3, 'KPI Achievement', { employee: employee.name, kpi: planKpi.kpi_name, actual: achievement.actual, target: targetValue, percent: achievement.percent });
124→        
125→        // Step 4: Determine slab
126→        const slabSet = slabSets[planKpi.kpi_id];
127→        const slabResult = determineSlab(achievement.percent, slabSet, overrides.slabs?.[planKpi.kpi_id]);
128→        log(4, 'Determine Slab', { employee: employee.name, kpi: planKpi.kpi_name, slab_type: slabResult.type, rate: slabResult.rate });
129→        
130→        // Step 5: Calculate KPI payout
131→        const kpiPayout = calculateKpiPayout(achievement, slabResult, empContext);
132→        log(5, 'KPI Payout', { employee: employee.name, kpi: planKpi.kpi_name, raw_payout: kpiPayout.amount });
133→        
134→        // Step 6: Apply weight
135→        const weighted = applyWeight(kpiPayout.amount, planKpi.weight);
136→        log(6, 'Apply Weight', { employee: employee.name, kpi: planKpi.kpi_name, weight: planKpi.weight, weighted_payout: weighted });
137→        
138→        kpiResults.push({
139→          kpi_id: planKpi.kpi_id,
140→          kpi_name: planKpi.kpi_name,
141→          kpi_code: planKpi.kpi_code,
142→          kpi_category: planKpi.kpi_category,
143→          unit: planKpi.unit,
144→          target_value: targetValue,
145→          actual_value: achievement.actual,
146→          achievement_percent: achievement.percent,
147→          slab_rate: slabResult.rate,
148→          slab_type: slabResult.type,
149→          raw_payout: kpiPayout.amount,
150→          weighted_payout: weighted,
151→          weight: planKpi.weight,
152→          calculation_details: JSON.stringify({
153→            achievement,
154→            slab: slabResult,
155→            payout: kpiPayout,
156→          }),
157→        });
158→      }
159→      
160→      // Step 7: Aggregate KPIs
161→      const grossPayout = aggregateKpis(kpiResults);
162→      log(7, 'Aggregate KPIs', { employee: employee.name, gross_payout: grossPayout });
163→      
164→      // Step 8: Apply multiplier
165→      const multiplierResult = applyMultiplier(grossPayout, multiplierRules, filtered, employee, period, db, overrides.multipliers);
166→      log(8, 'Apply Multiplier', { employee: employee.name, multiplier_amount: multiplierResult.amount, applied: multiplierResult.applied });
167→      
168→      // Step 9: Apply penalty
169→      const penaltyResult = applyPenalty(grossPayout + multiplierResult.amount, penaltyRules, filtered);
170→      log(9, 'Apply Penalty', { employee: employee.name, penalty_amount: penaltyResult.amount, triggered: penaltyResult.triggered });
171→      
172→      let netPayout = grossPayout + multiplierResult.amount - penaltyResult.amount;
173→      
174→      // Apply eligibility reduction
175→      if (eligibility.status === 'ineligible') {
176→        netPayout = 0;
177→      } else if (eligibility.status === 'reduced') {
178→        netPayout = netPayout * (1 - eligibility.reduction / 100);
179→      }
180→      
181→      // Step 10: Apply cap
182→      const capResult = applyCap(netPayout, cappingRules, employee);
183→      log(10, 'Apply Cap', { employee: employee.name, before: netPayout, after: capResult.capped, cap_hit: capResult.applied });
184→      
185→      netPayout = capResult.capped;
186→      
187→      // Handle split (adjust net payout for split roles)
188→      let splitAdjustment = 0;
189→      if (splitRules.length > 0) {
190→        for (const sr of splitRules) {
191→          const participant = sr.participants.find(p => p.role_id === employee.role_id);
192→          if (participant) {
193→            splitAdjustment = netPayout - (netPayout * participant.split_percent / 100);
194→            netPayout = netPayout * participant.split_percent / 100;
195→          }
196→        }
197→      }
198→      
199→      const payoutRecord = {
200→        employee,
201→        run_id: runId,
202→        gross_payout: grossPayout,
203→        multiplier_amount: multiplierResult.amount,
204→        penalty_amount: penaltyResult.amount,
205→        cap_adjustment: capResult.adjustment,
206→        split_adjustment: splitAdjustment,
207→        net_payout: Math.round(netPayout * 100) / 100,
208→        eligibility_status: eligibility.status,
209→        eligibility_details: eligibility.details,
210→        kpi_results: kpiResults,
211→        calculation_details: {
212→          multiplier: multiplierResult,
213→          penalty: penaltyResult,
214→          cap: capResult,
215→          eligibility,
216→        },
217→      };
218→      
219→      // Step 11: Store payout
220→      const payoutId = storePayout(db, payoutRecord, plan_id, period);
221→      log(11, 'Store Payout', { employee: employee.name, payout_id: payoutId, net_payout: payoutRecord.net_payout });
222→      
223→      // Step 12: Create approval entry (only for real runs)
224→      if (!is_simulation) {
225→        createApproval(db, payoutId);
226→        log(12, 'Create Approval', { employee: employee.name, status: 'submitted' });
227→      }
228→      
229→      allPayouts.push({ ...payoutRecord, id: payoutId });
230→    }
231→    
232→    // Step 13: Complete the run
233→    const totalPayout = allPayouts.reduce((sum, p) => sum + p.net_payout, 0);
234→    db.prepare(`
235→      UPDATE calculation_runs SET status = 'completed', total_payout = ?, employee_count = ?,
236→        completed_at = datetime('now'), calculation_details = ?
237→      WHERE id = ?
238→    `).run(Math.round(totalPayout * 100) / 100, allPayouts.length, JSON.stringify({ steps }), runId);
239→    log(13, 'Complete', { total_payout: totalPayout, employee_count: allPayouts.length });
240→    
241→    return {
242→      run_id: runId,
243→      plan_id,
244→      period,
245→      status: 'completed',
246→      is_simulation,
247→      total_payout: Math.round(totalPayout * 100) / 100,
248→      employee_count: allPayouts.length,
249→      payouts: allPayouts.map(p => ({
250→        employee_id: p.employee.id,
251→        employee_name: p.employee.name,
252→        role_name: p.employee.role_name,
253→        gross_payout: p.gross_payout,
254→        net_payout: p.net_payout,
255→        eligibility_status: p.eligibility_status,
256→      })),
257→      steps,
258→    };
259→  } catch (err) {
260→    db.prepare("UPDATE calculation_runs SET status = 'failed', completed_at = datetime('now') WHERE id = ?").run(runId);
261→    throw err;
262→  }
263→}
