 1→export function checkEligibility(transactions, eligibilityRules, context) {
 2→  if (!eligibilityRules || eligibilityRules.length === 0) {
 3→    return { status: 'eligible', reduction: 0, details: [] };
 4→  }
 5→  
 6→  const sales = transactions.filter(t => t.transaction_type === 'sale');
 7→  const returns = transactions.filter(t => t.transaction_type === 'return');
 8→  const collections = transactions.filter(t => t.transaction_type === 'collection');
 9→  
10→  const totalSales = sales.reduce((sum, t) => sum + t.amount, 0);
11→  const totalReturns = returns.reduce((sum, t) => sum + t.amount, 0);
12→  const totalCollections = collections.reduce((sum, t) => sum + t.amount, 0);
13→  
14→  const metrics = {
15→    min_sales: totalSales,
16→    min_collection_percent: totalSales > 0 ? (totalCollections / totalSales) * 100 : 0,
17→    max_return_percent: totalSales > 0 ? (totalReturns / totalSales) * 100 : 0,
18→    min_active_days: 22, // Default for prototype
19→    min_lines_sold: new Set(sales.map(t => t.product_id)).size,
20→  };
21→  
22→  let status = 'eligible';
23→  let reduction = 0;
24→  const details = [];
25→  
26→  for (const rule of eligibilityRules) {
27→    const metricValue = metrics[rule.metric] || 0;
28→    let passes = true;
29→    
30→    switch (rule.operator) {
31→      case '>=': passes = metricValue >= rule.threshold; break;
32→      case '<=': passes = metricValue <= rule.threshold; break;
33→      case '>': passes = metricValue > rule.threshold; break;
34→      case '<': passes = metricValue < rule.threshold; break;
35→      case '=': passes = metricValue === rule.threshold; break;
36→    }
37→    
38→    const detail = {
39→      metric: rule.metric,
40→      operator: rule.operator,
41→      threshold: rule.threshold,
42→      actual: Math.round(metricValue * 100) / 100,
43→      passed: passes,
44→      action: rule.action,
45→    };
46→    
47→    if (!passes) {
48→      switch (rule.action) {
49→        case 'zero_payout':
50→          status = 'ineligible';
51→          detail.impact = 'Payout set to zero';
52→          break;
53→        case 'reduce_percent':
54→          if (status !== 'ineligible') status = 'reduced';
55→          reduction = Math.max(reduction, rule.reduction_percent);
56→          detail.impact = `Payout reduced by ${rule.reduction_percent}%`;
57→          break;
58→        case 'warning_only':
59→          detail.impact = 'Warning only - no payout impact';
60→          break;
61→      }
62→    }
63→    
64→    details.push(detail);
65→  }
66→  
67→  return { status, reduction, details };
68→}
