  1→export function determineSlab(achievementPercent, slabSet, overrides) {
  2→  if (!slabSet) {
  3→    // No slab configured - use linear interpolation
  4→    return {
  5→      type: 'linear',
  6→      rate: achievementPercent >= 70 ? Math.min(achievementPercent / 100, 1.5) * 5 : 0,
  7→      tier: null,
  8→      details: 'No slab configured, using linear rate',
  9→    };
 10→  }
 11→  
 12→  const tiers = overrides?.tiers || slabSet.tiers;
 13→  const type = slabSet.type;
 14→  
 15→  switch (type) {
 16→    case 'step':
 17→      return calculateStepSlab(achievementPercent, tiers);
 18→    case 'progressive':
 19→      return calculateProgressiveSlab(achievementPercent, tiers);
 20→    case 'accelerator':
 21→      return calculateAcceleratorSlab(achievementPercent, tiers);
 22→    default:
 23→      return { type: 'unknown', rate: 0, tier: null, details: `Unknown slab type: ${type}` };
 24→  }
 25→}
 26→
 27→// Step slab: flat rate based on which tier the achievement falls into
 28→function calculateStepSlab(percent, tiers) {
 29→  let matchedTier = null;
 30→  
 31→  for (const tier of tiers) {
 32→    const max = tier.max_percent ?? Infinity;
 33→    if (percent >= tier.min_percent && percent < max) {
 34→      matchedTier = tier;
 35→      break;
 36→    }
 37→    // Handle the last open-ended tier
 38→    if (tier.max_percent === null && percent >= tier.min_percent) {
 39→      matchedTier = tier;
 40→      break;
 41→    }
 42→  }
 43→  
 44→  return {
 45→    type: 'step',
 46→    rate: matchedTier?.rate || 0,
 47→    rate_type: matchedTier?.rate_type || 'percentage',
 48→    tier: matchedTier?.tier_order || 0,
 49→    details: matchedTier ? `Tier ${matchedTier.tier_order}: ${matchedTier.min_percent}%-${matchedTier.max_percent ?? '∞'}% = ${matchedTier.rate}%` : 'Below minimum tier',
 50→  };
 51→}
 52→
 53→// Progressive slab: rate applied to portion within each tier
 54→function calculateProgressiveSlab(percent, tiers) {
 55→  let totalRate = 0;
 56→  const breakdown = [];
 57→  
 58→  for (const tier of tiers) {
 59→    const max = tier.max_percent ?? Infinity;
 60→    if (percent <= tier.min_percent) break;
 61→    
 62→    const applicable = Math.min(percent, max) - tier.min_percent;
 63→    const tierContribution = applicable * tier.rate / 100;
 64→    totalRate += tierContribution;
 65→    
 66→    breakdown.push({
 67→      tier: tier.tier_order,
 68→      range: `${tier.min_percent}%-${tier.max_percent ?? '∞'}%`,
 69→      applicable_percent: applicable,
 70→      rate: tier.rate,
 71→      contribution: tierContribution,
 72→    });
 73→  }
 74→  
 75→  return {
 76→    type: 'progressive',
 77→    rate: Math.round(totalRate * 100) / 100,
 78→    rate_type: tiers[0]?.rate_type || 'percentage',
 79→    tier: breakdown.length,
 80→    details: breakdown,
 81→  };
 82→}
 83→
 84→// Accelerator: base rate below 100%, accelerated rate above 100%
 85→function calculateAcceleratorSlab(percent, tiers) {
 86→  let rate = 0;
 87→  let matchedTier = null;
 88→  
 89→  // Below 100%: use base tier rate
 90→  // Above 100%: use accelerated tier rate for the entire amount
 91→  for (const tier of tiers) {
 92→    const max = tier.max_percent ?? Infinity;
 93→    if (percent >= tier.min_percent && percent < max) {
 94→      matchedTier = tier;
 95→      rate = tier.rate;
 96→      break;
 97→    }
 98→    if (tier.max_percent === null && percent >= tier.min_percent) {
 99→      matchedTier = tier;
100→      rate = tier.rate;
101→      break;
102→    }
103→  }
104→  
105→  return {
106→    type: 'accelerator',
107→    rate,
108→    rate_type: matchedTier?.rate_type || 'percentage',
109→    tier: matchedTier?.tier_order || 0,
110→    is_accelerated: percent > 100,
111→    details: `${percent > 100 ? 'Accelerated' : 'Base'} rate: ${rate}%`,
112→  };
113→}
