### 3. Engine Evaluation Logic

#### 3A. New File: `formulaEvaluator.js`

Create `/Users/fci/Desktop/Prakash/Commission/server/src/engine/formulaEvaluator.js`.

This is the core of the dynamic engine. It exports a single function:

```js
export function evaluateFormula(formula, transactions, employee, period, db)
```

**Implementation logic:**

```js
export function evaluateFormula(formulaJson, transactions, employee, period, db) {
  // Parse formula if string
  let formula;
  try {
    formula = typeof formulaJson === 'string' ? JSON.parse(formulaJson) : formulaJson;
  } catch {
    return null;  // unparseable legacy formula, signal to use fallback
  }

  // If formula doesn't have a valid .type, return null (legacy)
  if (!formula || !formula.type) return null;

  switch (formula.type) {
    case 'simple':
      return evaluateSimple(formula, transactions);
    case 'ratio':
      return evaluateRatio(formula, transactions);
    case 'growth':
      return evaluateGrowth(formula, transactions, employee, period, db);
    case 'team':
      return evaluateTeam(formula, transactions, employee, period, db);
    case 'static':
      return formula.defaultValue ?? 0;
    default:
      return null;
  }
}
```

**Helper: `filterTransactions(transactions, config)`**

Shared filter function used by all types:

```js
function filterTransactions(transactions, config) {
  let filtered = transactions;

  // Filter by transaction type
  if (config.transactionType && config.transactionType !== 'all') {
    filtered = filtered.filter(t => t.transaction_type === config.transactionType);
  }

  // Apply attribute filters
  for (const f of (config.filters || [])) {
    filtered = filtered.filter(t => {
      const val = t[f.field];
      switch (f.operator) {
        case '=':      return val == f.value;   // loose equality for 0/1 vs boolean
        case '!=':     return val != f.value;
        case 'in':     return Array.isArray(f.value) && f.value.includes(val);
        case 'not_in': return Array.isArray(f.value) && !f.value.includes(val);
        default:       return true;
      }
    });
  }

  return filtered;
}
```

**Helper: `aggregate(transactions, aggregation, field)`**

```js
function aggregate(txns, aggregation, field) {
  switch (aggregation) {
    case 'SUM':
      return txns.reduce((sum, t) => sum + (Number(t[field]) || 0), 0);
    case 'COUNT_DISTINCT':
      return new Set(txns.map(t => t[field])).size;
    case 'AVG': {
      if (txns.length === 0) return 0;
      const total = txns.reduce((sum, t) => sum + (Number(t[field]) || 0), 0);
      return total / txns.length;
    }
    case 'COUNT':
      return txns.length;
    default:
      return 0;
  }
}
```

**`evaluateSimple`:**
```js
function evaluateSimple(formula, transactions) {
  const filtered = filterTransactions(transactions, formula);
  return aggregate(filtered, formula.aggregation, formula.field);
}
```

**`evaluateRatio`:**
```js
function evaluateRatio(formula, transactions) {
  const numTxns = filterTransactions(transactions, formula.numerator);
  const denTxns = filterTransactions(transactions, formula.denominator);
  const num = aggregate(numTxns, formula.numerator.aggregation, formula.numerator.field);
  const den = aggregate(denTxns, formula.denominator.aggregation, formula.denominator.field);
  if (den === 0) return 0;
  return (num / den) * (formula.multiplyBy || 1);
}
```

**`evaluateGrowth`:**
```js
function evaluateGrowth(formula, transactions, employee, period, db) {
  // Current period value from in-memory transactions
  const currentFiltered = filterTransactions(transactions, formula.baseMetric);
  const currentValue = aggregate(currentFiltered, formula.baseMetric.aggregation, formula.baseMetric.field);

  // Compute previous period string
  const [year, month] = period.split('-').map(Number);
  let prevPeriod;
  switch (formula.compareWith) {
    case 'previous_year':    prevPeriod = `${year - 1}-${String(month).padStart(2, '0')}`; break;
    case 'previous_month':   /* handle month rollback */ break;
    case 'previous_quarter': /* handle quarter rollback */ break;
    default:                 prevPeriod = `${year - 1}-${String(month).padStart(2, '0')}`;
  }

  // Query DB for previous period (same approach as current step03 line 19-22)
  const prevRow = db.prepare(`
    SELECT COALESCE(SUM(${formula.baseMetric.field === 'amount' ? 'amount' : 'quantity'}), 0) as prev
    FROM transactions
    WHERE employee_id = ? AND period = ? AND transaction_type = ?
  `).get(employee.id, prevPeriod, formula.baseMetric.transactionType || 'sale');

  const prevValue = prevRow.prev;
  return prevValue > 0 ? ((currentValue - prevValue) / prevValue) * 100 : 0;
}
```

Note on growth queries: The DB query for previous period is intentionally kept simple (matching the current pattern on line 19-22 of step03). Attribute filters on previous period transactions are not applied because the DB query doesn't JOIN products/customers. If needed in the future, the growth evaluator can be enhanced to do a full JOIN, but that is out of scope for Tier 1.

**`evaluateTeam`:**
```js
function evaluateTeam(formula, transactions, employee, period, db) {
  const reports = db.prepare('SELECT id FROM employees WHERE reports_to = ?').all(employee.id);
  const values = [];

  for (const rep of reports) {
    // Fetch each report's transactions (reusing step01 function)
    const repTxns = db.prepare(`
      SELECT t.*, p.is_strategic, p.is_new_launch, p.category as product_category,
             c.channel as customer_channel
      FROM transactions t
      JOIN products p ON t.product_id = p.id
      JOIN customers c ON t.customer_id = c.id
      WHERE t.employee_id = ? AND t.period = ?
    `).all(rep.id, period);

    const filtered = filterTransactions(repTxns, formula.baseMetric);
    values.push(aggregate(filtered, formula.baseMetric.aggregation, formula.baseMetric.field));
  }

  switch (formula.teamAggregation) {
    case 'SUM': return values.reduce((a, b) => a + b, 0);
    case 'AVG': return values.length > 0 ? values.reduce((a, b) => a + b, 0) / values.length : 0;
    default:    return values.reduce((a, b) => a + b, 0);
  }
}
```

