function migrateFormulas(db) {
  // Check if migration already done (first KPI has JSON formula)
  const first = db.prepare('SELECT formula FROM kpi_definitions LIMIT 1').get();
  if (!first) return;
  try {
    const parsed = JSON.parse(first.formula);
    if (parsed && parsed.type) return;  // Already migrated
  } catch { /* needs migration */ }

  // Map kpi_code -> new formula JSON
  const formulaMap = {
    'TOTAL_REVENUE': { type: 'simple', aggregation: 'SUM', field: 'amount', transactionType: 'sale', filters: [] },
    // ... all 15 KPIs as listed above ...
  };

  const stmt = db.prepare('UPDATE kpi_definitions SET formula = ? WHERE code = ?');
  const tx = db.transaction(() => {
    for (const [code, formula] of Object.entries(formulaMap)) {
      stmt.run(JSON.stringify(formula), code);
    }
  });
  tx();
  console.log('Migrated KPI formulas to structured JSON');
}
```

This is idempotent: it checks whether the first KPI already has a valid JSON formula before running.

